// Validează input-ul și mapează platform → marketplace
const body = $input.first().json.body || {};
const sourcePlatform = (body.sourcePlatform || '').toLowerCase();
const targetPlatform = (body.targetPlatform || '').toLowerCase();
const platformMap = {
  'emag': 'emag_ro',
  'trendyol': 'trendyol_ro',
  'temu': 'temu_ro'
};
const targetMarketplace = platformMap[targetPlatform] || (targetPlatform + '_ro');
const targetCategoryId = String(body.targetCategoryId || '').trim();
const targetAttrId = String(body.targetAttrId || '').trim();
const sourceAttrName = String(body.sourceAttrName || '').trim();
const sourceValue = String(body.sourceValue || '').trim();
const productTitle = String(body.productTitle || '').slice(0, 200);

if (!targetCategoryId || !targetAttrId || !sourceValue) {
  return [{ json: { _error: 'missing required fields', value: null, _skipQuery: true } }];
}

return [{ json: { sourcePlatform, targetPlatform, targetMarketplace, targetCategoryId, targetAttrId, sourceAttrName, sourceValue, productTitle } }];

const https = require('https');

// ─── CONFIGURARE API ────────────────────────────────────────────────────────
const GEMINI_API_KEY = 'PUNE_GEMINI_API_KEY_AICI';
const MODEL_PRIMARY  = 'gemini-3.1-flash-lite-preview';
const MODEL_FALLBACK = 'gemini-flash-latest';
// ────────────────────────────────────────────────────────────────────────────

function httpsRequest(options, postBody) {
  return new Promise((resolve, reject) => {
    const req = https.request(options, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({ status: res.statusCode, body: Buffer.concat(chunks) }));
    });
    req.on('error', reject);
    if (postBody) req.write(postBody);
    req.end();
  });
}

async function callGemini(model, reqBodyStr) {
  const res = await httpsRequest({
    hostname: 'generativelanguage.googleapis.com',
    path: `/v1beta/models/${model}:generateContent?key=${GEMINI_API_KEY}`,
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(reqBodyStr)
    }
  }, reqBodyStr);
  if (res.status >= 500) throw new Error(`HTTP ${res.status} from Gemini`);
  return res;
}

const prep = $('Prepare Input').first().json;
if (prep._skipQuery) {
  return [{ json: { value: null, _error: prep._error } }];
}

const { sourceAttrName, sourceValue, productTitle } = prep;
const rows = $input.all().map(i => i.json).filter(r => r && r.characteristic_name != null);

if (!rows.length) {
  return [{ json: { value: null, _error: 'target attribute not found' } }];
}

const targetRow = rows[0];
const targetAttrName = targetRow.characteristic_name;
const allowsCustom = targetRow.allows_custom === true;
let values = targetRow.attr_values || [];
if (typeof values === 'string') { try { values = JSON.parse(values); } catch(e) { values = []; } }
const valueNames = values.map(v => v && v.name).filter(Boolean);

const systemInstruction = `Mapează o valoare de atribut de pe un marketplace pe altul. Returnează DOAR JSON valid: {"value": "<string>"} sau {"value": null}.\n\nReguli:\n1. Dacă există un match semantic în lista de valori valide, returnează EXACT acea valoare (string identic).\n2. Dacă NU există match ȘI allowsCustom=true, returnează o valoare custom scurtă (1-3 cuvinte) bazată pe valoarea sursă.\n3. Dacă NU există match ȘI allowsCustom=false, returnează {"value": null}.\n4. NU returna explicații, doar JSON.`;

const userText = `Atribut sursă: ${sourceAttrName}\nValoare sursă: ${sourceValue}\n\nAtribut țintă: ${targetAttrName}\nValori valide pentru țintă: ${JSON.stringify(valueNames)}\nPermite valori custom: ${allowsCustom}\n\nContext produs: ${productTitle}`;

const reqBody = {
  systemInstruction: { parts: [{ text: systemInstruction }] },
  contents: [{ role: 'user', parts: [{ text: userText }] }],
  generationConfig: {
    temperature: 0.1,
    responseMimeType: 'application/json',
    responseSchema: {
      type: 'object',
      properties: { value: { type: 'string', nullable: true } },
      required: ['value']
    }
  }
};

const reqBodyStr = JSON.stringify(reqBody);
let geminiResponse;
try {
  geminiResponse = await callGemini(MODEL_PRIMARY, reqBodyStr);
} catch (err) {
  try {
    geminiResponse = await callGemini(MODEL_FALLBACK, reqBodyStr);
  } catch (err2) {
    return [{ json: { value: null, _error: 'gemini failed: ' + err2.message } }];
  }
}

try {
  const parsed = JSON.parse(geminiResponse.body.toString('utf8'));
  const text = parsed?.candidates?.[0]?.content?.parts?.[0]?.text;
  if (text) {
    const json = JSON.parse(text);
    const out = json && typeof json.value === 'string' ? json.value : null;
    return [{ json: { value: out } }];
  }
} catch (e) {
  return [{ json: { value: null, _error: 'parse failed: ' + e.message } }];
}

return [{ json: { value: null } }];
